from pathlib import Path

for path in Path('docs').glob('*.md'):
    text = path.read_text(encoding='utf-8')
    lines = text.splitlines()

    try:
        start = lines.index('## 复杂度分析')
    except ValueError:
        continue

    end = len(lines)
    for i in range(start + 1, len(lines)):
        if lines[i].startswith('## '):
            end = i
            break

    complexity_block = lines[start + 1:end]
    while complexity_block and complexity_block[0].strip() == '':
        complexity_block.pop(0)
    while complexity_block and complexity_block[-1].strip() == '':
        complexity_block.pop()

    # Remove the original complexity section
    new_lines = lines[:start] + lines[end:]

    # Insert before code section so complexity remains within 思路 part
    try:
        code_idx = new_lines.index('## 代码')
    except ValueError:
        code_idx = len(new_lines)

    insert_block = ['### 复杂度分析', ''] + complexity_block + ['']
    new_lines = new_lines[:code_idx] + insert_block + new_lines[code_idx:]

    # normalize extra blank lines
    normalized = []
    blank = 0
    for line in new_lines:
        if line.strip() == '':
            blank += 1
            if blank <= 2:
                normalized.append(line)
        else:
            blank = 0
            normalized.append(line)

    path.write_text('\n'.join(normalized).rstrip() + '\n', encoding='utf-8')
